    self.bannerAdEnableShow = configs.adsBannerEnableShow;    // banner广告是否显示
    self.nativeAdEnableShow = configs.adsNativeEnableShow;    // 信息流广告是否显示
    self.rewardAdEnableShow = configs.adsRewardFloatingEnableShow;  // 激励广告悬浮窗是否展示
    self.myVCRewardAdRowEnableShow = configs.adsRewardMyVCEnableShow;     // "我的"界面，看广告行是否展示

    // 展示位置
    self.bannerAdPosition = configs.bannerAdPosition;
    self.nativeAdPosition = configs.nativeAdPosition;

    if ([self isAdsAppIdValid:configs.adsAppId]) {
        [self.userDefaults setValue:configs.adsAppId forKey:kWBAdsAppId];
    }

    self.HeartBeatRate = configs.hb_rate;
    self.LogRate = configs.log_rate;

