- (void)createOrderWithProduct:(WBProductModel *)product payMethod:(NSUInteger)method pageSource:(NSString *)pageSource callback:(WBNetworkBaseCallback)callback {
    NSString *productId = product.apple_product_id;
    BOOL isUpgrade = (product.typeFlags & WBProductTypeFlagUpgrade) != 0;
    NSMutableDictionary *params = [NSMutableDictionary dictionaryWithDictionary:@{
        @"apple_product_id" : productId,
        @"param": @(method),
        @"source": pageSource,
        @"isUpgrade": @(isUpgrade),
        @"paymentMethodId": product.selectedPayMethodId
    }];
    if ([product.selectedPromoModels count]) {
        NSString *promoCodes = [[product.selectedPromoModels valueForKey:NSStringFromSelector(@selector(code))] componentsJoinedByString:@","];
        params[@"codes"] = promoCodes;
    }
    [self POST:@"order/create" params:params callback:callback];
}

